-- Verify insertion
SELECT
  COUNT(*) as total_properties,
  COUNT(DISTINCT city_name) as total_cities,
  COUNT(DISTINCT NULL) as total_neighborhoods
FROM properties;

-- Show properties by city and neighborhood
SELECT
  city_name,
  NULL,
  COUNT(*) as property_count
FROM properties
GROUP BY city_name, NULL
ORDER BY city_name, NULL;
